import{SupervisorService}from"./supervisor.service.js";async function initSupervisor(){let t=document.querySelector(".cuerpoTabla");var e;t&&(e=await SupervisorService.get_all_supervisores(),t.innerHTML="",console.log(e),e.forEach(e=>{t.innerHTML+=`
            <tr>
                <td>${e.id_supervisor}</td>
                <td>${e.nombre}</td>
                <td>${e.cedula}</td>
                <td>
                    <button class="btn btn-danger"><i class="bi bi-trash"></i></button>
                    <button class="btn btn-warning"><i class="bi bi-repeat"></i></button>
                </td>
            </tr>
        `}),$.fn.DataTable.isDataTable("#dataTable")&&$("#dataTable").DataTable().destroy(),$("#dataTable").DataTable({responsive:!0}),console.log(document.querySelector(".cuerpoTabla")))}export{initSupervisor};